/**
 * 3D mesh fixtures for the game-dev/DCC format batch (FBX, DAE, 3DS, PLY,
 * glTF JSON, USDZ). Every fixture encodes the SAME ground-truth solid: a cube
 * of edge length 2 centered on the origin (vertices at ±1), 8 vertices, 12
 * triangles, all faces wound outward (CCW seen from outside).
 *
 * That shape gives tests a strong invariant: the signed volume computed from
 * the triangle soup must equal exactly 8.0. A wrong vertex, a misread index,
 * a transposed axis, or a dropped face all change the volume, so asserting
 * volume + triangle count verifies the whole parse/convert/build pipeline,
 * not just "it didn't throw".
 *
 * All fixtures are hand-written against the respective format specs (not
 * generated by our own writers), so tests are independent of the code under
 * test.
 */

// 8 corners of the ±1 cube.
export const CUBE_VERTICES: ReadonlyArray<readonly [number, number, number]> = [
  [-1, -1, -1], // 0
  [1, -1, -1], // 1
  [1, 1, -1], // 2
  [-1, 1, -1], // 3
  [-1, -1, 1], // 4
  [1, -1, 1], // 5
  [1, 1, 1], // 6
  [-1, 1, 1], // 7
];

// 12 outward-wound triangles.
export const CUBE_TRIANGLES: ReadonlyArray<readonly [number, number, number]> = [
  [0, 2, 1], [0, 3, 2], // bottom (z = -1)
  [4, 5, 6], [4, 6, 7], // top (z = +1)
  [0, 1, 5], [0, 5, 4], // front (y = -1)
  [1, 2, 6], [1, 6, 5], // right (x = +1)
  [2, 3, 7], [2, 7, 6], // back (y = +1)
  [3, 0, 4], [3, 4, 7], // left (x = -1)
];

export const CUBE_TRIANGLE_COUNT = 12;
export const CUBE_VOLUME = 8;

const V = CUBE_VERTICES;
const T = CUBE_TRIANGLES;

/**
 * Signed volume of a triangle soup via the divergence theorem:
 * sum over triangles of dot(a, cross(b, c)) / 6. Exact for closed meshes;
 * outward winding gives a positive result. Used by tests to verify converted
 * geometry, robust to vertex reordering/deduplication/splitting.
 */
export function meshVolume(vertices: ArrayLike<number>, triangles: ArrayLike<number>): number {
  let vol = 0;
  for (let t = 0; t + 2 < triangles.length; t += 3) {
    const a = triangles[t] * 3;
    const b = triangles[t + 1] * 3;
    const c = triangles[t + 2] * 3;
    const ax = vertices[a], ay = vertices[a + 1], az = vertices[a + 2];
    const bx = vertices[b], by = vertices[b + 1], bz = vertices[b + 2];
    const cx = vertices[c], cy = vertices[c + 1], cz = vertices[c + 2];
    vol += ax * (by * cz - bz * cy) + ay * (bz * cx - bx * cz) + az * (bx * cy - by * cx);
  }
  return vol / 6;
}

// ---- PLY (ASCII) --------------------------------------------------------

export const CUBE_PLY_ASCII = `ply
format ascii 1.0
comment hand-written cube fixture
element vertex 8
property float x
property float y
property float z
element face 12
property list uchar int vertex_indices
end_header
${V.map((v) => v.join(" ")).join("\n")}
${T.map((t) => `3 ${t.join(" ")}`).join("\n")}
`;

/** Binary little-endian PLY of the same cube (built per spec, byte by byte). */
export function makeCubePlyBinary(): Uint8Array {
  const header =
    "ply\n" +
    "format binary_little_endian 1.0\n" +
    "element vertex 8\n" +
    "property float x\n" +
    "property float y\n" +
    "property float z\n" +
    "element face 12\n" +
    "property list uchar int vertex_indices\n" +
    "end_header\n";
  const headerBytes = new TextEncoder().encode(header);
  // 8 vertices * 12 bytes + 12 faces * (1 + 12) bytes
  const body = new ArrayBuffer(8 * 12 + 12 * 13);
  const view = new DataView(body);
  let off = 0;
  for (const v of V) {
    view.setFloat32(off, v[0], true);
    view.setFloat32(off + 4, v[1], true);
    view.setFloat32(off + 8, v[2], true);
    off += 12;
  }
  for (const t of T) {
    view.setUint8(off, 3);
    view.setInt32(off + 1, t[0], true);
    view.setInt32(off + 5, t[1], true);
    view.setInt32(off + 9, t[2], true);
    off += 13;
  }
  const out = new Uint8Array(headerBytes.length + body.byteLength);
  out.set(headerBytes, 0);
  out.set(new Uint8Array(body), headerBytes.length);
  return out;
}

// ---- glTF 2.0 (.gltf JSON with embedded data-URI buffer) -----------------

function base64FromBytes(bytes: Uint8Array): string {
  let bin = "";
  for (const b of bytes) bin += String.fromCharCode(b);
  // btoa exists in happy-dom and browsers; Buffer path covers plain node.
  return typeof btoa === "function" ? btoa(bin) : Buffer.from(bytes).toString("base64");
}

/**
 * Minimal spec-conformant .gltf JSON: positions + uint16 indices in a single
 * data-URI buffer, plus a named PBR material so container-repack tests can
 * assert materials survive gltf -> glb -> gltf losslessly.
 */
export function makeCubeGltfJson(): string {
  const posBytes = 8 * 3 * 4;
  const idxBytes = 12 * 3 * 2;
  const buf = new ArrayBuffer(posBytes + idxBytes);
  const posView = new Float32Array(buf, 0, 24);
  V.forEach((v, i) => posView.set(v, i * 3));
  const idxView = new Uint16Array(buf, posBytes, 36);
  T.forEach((t, i) => idxView.set(t, i * 3));

  const gltf = {
    asset: { version: "2.0", generator: "fixture" },
    scene: 0,
    scenes: [{ nodes: [0] }],
    nodes: [{ mesh: 0, name: "Cube" }],
    meshes: [{ primitives: [{ attributes: { POSITION: 0 }, indices: 1, material: 0, mode: 4 }] }],
    materials: [
      {
        name: "FixtureRed",
        pbrMetallicRoughness: { baseColorFactor: [1, 0, 0, 1], metallicFactor: 0.25 },
      },
    ],
    accessors: [
      { bufferView: 0, componentType: 5126, count: 8, type: "VEC3", min: [-1, -1, -1], max: [1, 1, 1] },
      { bufferView: 1, componentType: 5123, count: 36, type: "SCALAR" },
    ],
    bufferViews: [
      { buffer: 0, byteOffset: 0, byteLength: posBytes, target: 34962 },
      { buffer: 0, byteOffset: posBytes, byteLength: idxBytes, target: 34963 },
    ],
    buffers: [
      {
        byteLength: buf.byteLength,
        uri: `data:application/octet-stream;base64,${base64FromBytes(new Uint8Array(buf))}`,
      },
    ],
  };
  return JSON.stringify(gltf);
}

