// ---- FBX (ASCII 7.4) -----------------------------------------------------

/**
 * ASCII FBX with the node subset three's FBXLoader requires: header with
 * FBXVersion >= 7000, a Geometry (Vertices + PolygonVertexIndex, where the
 * final index of each polygon is encoded as -(index + 1)), a Model of type
 * Mesh, and OO connections geometry -> model -> root(0).
 */
export const CUBE_FBX_ASCII = `; FBX 7.4.0 project file
FBXHeaderExtension:  {
	FBXHeaderVersion: 1003
	FBXVersion: 7400
	Creator: "fixture"
}
GlobalSettings:  {
	Version: 1000
	Properties70:  {
		P: "UpAxis", "int", "Integer", "",1
		P: "UpAxisSign", "int", "Integer", "",1
		P: "FrontAxis", "int", "Integer", "",2
		P: "FrontAxisSign", "int", "Integer", "",1
		P: "CoordAxis", "int", "Integer", "",0
		P: "CoordAxisSign", "int", "Integer", "",1
		P: "UnitScaleFactor", "double", "Number", "",1
	}
}
Objects:  {
	Geometry: 1000, "Geometry::Cube", "Mesh" {
		Vertices: *24 {
			a: ${V.map((v) => v.join(",")).join(",")}
		}
		PolygonVertexIndex: *36 {
			a: ${T.map((t) => `${t[0]},${t[1]},${-(t[2] + 1)}`).join(",")}
		}
		GeometryVersion: 124
	}
	Model: 2000, "Model::Cube", "Mesh" {
		Version: 232
		Properties70:  {
		}
		Shading: T
		Culling: "CullingOff"
	}
}
Connections:  {
	C: "OO",1000,2000
	C: "OO",2000,0
}
`;

// ---- OBJ / STL / GLB sources (same cube, hand-built per spec) -------------

export const CUBE_OBJ = `# cube fixture
${V.map((v) => `v ${v.join(" ")}`).join("\n")}
${T.map((t) => `f ${t[0] + 1} ${t[1] + 1} ${t[2] + 1}`).join("\n")}
`;

/** Binary STL of the cube (80-byte header, u32 count, 50 bytes per tri). */
export function makeCubeStlBinary(): Uint8Array {
  const out = new Uint8Array(84 + 12 * 50);
  const view = new DataView(out.buffer);
  view.setUint32(80, 12, true);
  let off = 84;
  for (const t of T) {
    off += 12; // zero normal; readers recompute
    for (const vi of t) {
      view.setFloat32(off, V[vi][0], true);
      view.setFloat32(off + 4, V[vi][1], true);
      view.setFloat32(off + 8, V[vi][2], true);
      off += 12;
    }
    off += 2; // attribute byte count
  }
  return out;
}

/**
 * GLB of the cube, hand-built per the container spec. When `interleaved` is
 * set, positions share a bufferView with a dummy vec3 (byteStride 24), which
 * exercises the strided accessor path that naive readers corrupt.
 */
export function makeCubeGlb(interleaved = false): Uint8Array {
  const enc = new TextEncoder();
  let json: object;
  let bin: Uint8Array;

  if (!interleaved) {
    const posBytes = 8 * 12;
    const idxBytes = 36 * 2;
    bin = new Uint8Array(posBytes + idxBytes);
    const pv = new Float32Array(bin.buffer, 0, 24);
    V.forEach((v, i) => pv.set(v, i * 3));
    const iv = new Uint16Array(bin.buffer, posBytes, 36);
    T.forEach((t, i) => iv.set(t, i * 3));
    json = {
      asset: { version: "2.0" },
      scene: 0,
      scenes: [{ nodes: [0] }],
      nodes: [{ mesh: 0 }],
      meshes: [{ primitives: [{ attributes: { POSITION: 0 }, indices: 1, mode: 4 }] }],
      accessors: [
        { bufferView: 0, componentType: 5126, count: 8, type: "VEC3", min: [-1, -1, -1], max: [1, 1, 1] },
        { bufferView: 1, componentType: 5123, count: 36, type: "SCALAR" },
      ],
      bufferViews: [
        { buffer: 0, byteOffset: 0, byteLength: posBytes },
        { buffer: 0, byteOffset: posBytes, byteLength: idxBytes },
      ],
      buffers: [{ byteLength: bin.length }],
    };
  } else {
    // Interleave position + a dummy normal per vertex: stride 24 bytes.
    const stride = 24;
    const vtxBytes = 8 * stride;
    const idxBytes = 36 * 2;
    bin = new Uint8Array(vtxBytes + idxBytes);
    const view = new DataView(bin.buffer);
    V.forEach((v, i) => {
      view.setFloat32(i * stride, v[0], true);
      view.setFloat32(i * stride + 4, v[1], true);
      view.setFloat32(i * stride + 8, v[2], true);
      view.setFloat32(i * stride + 12, 9, true); // junk a naive reader would ingest
      view.setFloat32(i * stride + 16, 9, true);
      view.setFloat32(i * stride + 20, 9, true);
    });
    const iv = new Uint16Array(bin.buffer, vtxBytes, 36);
    T.forEach((t, i) => iv.set(t, i * 3));
    json = {
      asset: { version: "2.0" },
      scene: 0,
      scenes: [{ nodes: [0] }],
      nodes: [{ mesh: 0 }],
      meshes: [
        { primitives: [{ attributes: { POSITION: 0, NORMAL: 1 }, indices: 2, mode: 4 }] },
      ],
      accessors: [
        { bufferView: 0, byteOffset: 0, componentType: 5126, count: 8, type: "VEC3", min: [-1, -1, -1], max: [1, 1, 1] },
        { bufferView: 0, byteOffset: 12, componentType: 5126, count: 8, type: "VEC3" },
        { bufferView: 1, componentType: 5123, count: 36, type: "SCALAR" },
      ],
      bufferViews: [
        { buffer: 0, byteOffset: 0, byteLength: vtxBytes, byteStride: stride },
        { buffer: 0, byteOffset: vtxBytes, byteLength: idxBytes },
      ],
      buffers: [{ byteLength: bin.length }],
    };
  }

  const jsonBytes = enc.encode(JSON.stringify(json));
  const jsonPadded = (jsonBytes.length + 3) & ~3;
  const binPadded = (bin.length + 3) & ~3;
  const total = 12 + 8 + jsonPadded + 8 + binPadded;
  const out = new Uint8Array(total);
  const view = new DataView(out.buffer);
  view.setUint32(0, 0x46546c67, true);
  view.setUint32(4, 2, true);
  view.setUint32(8, total, true);
  view.setUint32(12, jsonPadded, true);
  view.setUint32(16, 0x4e4f534a, true);
  out.set(jsonBytes, 20);
  for (let i = jsonBytes.length; i < jsonPadded; i++) out[20 + i] = 0x20;
  const binHeader = 20 + jsonPadded;
  view.setUint32(binHeader, binPadded, true);
  view.setUint32(binHeader + 4, 0x004e4942, true);
  out.set(bin, binHeader + 8);
  return out;
}

/** .gltf whose single node scales the cube by 0.5 (expected volume: 1). */
export function makeScaledCubeGltfJson(): string {
  const doc = JSON.parse(makeCubeGltfJson()) as { nodes: Array<Record<string, unknown>> };
  doc.nodes[0] = { mesh: 0, scale: [0.5, 0.5, 0.5], translation: [10, 0, 0] };
  return JSON.stringify(doc);
}

// ---- 3DS (Autodesk 3D Studio, binary chunks) -----------------------------

/**
 * Minimal binary 3DS built chunk by chunk per the classic spec:
 * 0x4D4D main > 0x3D3D editor > 0x4000 named object > 0x4100 tri-mesh
 * > 0x4110 point array + 0x4120 face array.
 */
export function makeCube3ds(): Uint8Array {
  const enc = (id: number, payload: Uint8Array): Uint8Array => {
    const out = new Uint8Array(6 + payload.length);
    const view = new DataView(out.buffer);
    view.setUint16(0, id, true);
    view.setUint32(2, out.length, true);
    out.set(payload, 6);
    return out;
  };
  const concat = (...parts: Uint8Array[]): Uint8Array => {
    const total = parts.reduce((n, p) => n + p.length, 0);
    const out = new Uint8Array(total);
    let off = 0;
    for (const p of parts) {
      out.set(p, off);
      off += p.length;
    }
    return out;
  };

  // 0x4110 POINT_ARRAY: uint16 count + count * 3 float32
  const points = new Uint8Array(2 + 8 * 12);
  {
    const view = new DataView(points.buffer);
    view.setUint16(0, 8, true);
    V.forEach((v, i) => {
      view.setFloat32(2 + i * 12, v[0], true);
      view.setFloat32(2 + i * 12 + 4, v[1], true);
      view.setFloat32(2 + i * 12 + 8, v[2], true);
    });
  }
  // 0x4120 FACE_ARRAY: uint16 count + count * (3 x uint16 index + uint16 flags)
  const faces = new Uint8Array(2 + 12 * 8);
  {
    const view = new DataView(faces.buffer);
    view.setUint16(0, 12, true);
    T.forEach((t, i) => {
      view.setUint16(2 + i * 8, t[0], true);
      view.setUint16(2 + i * 8 + 2, t[1], true);
      view.setUint16(2 + i * 8 + 4, t[2], true);
      view.setUint16(2 + i * 8 + 6, 7, true); // ABC edge-visibility flags
    });
  }

  const triMesh = enc(0x4100, concat(enc(0x4110, points), enc(0x4120, faces)));
  const objName = new TextEncoder().encode("cube\0");
  const namedObject = enc(0x4000, concat(objName, triMesh));
  const meshVersion = new Uint8Array(4);
  new DataView(meshVersion.buffer).setUint32(0, 3, true);
  const editor = enc(0x3d3d, concat(enc(0x3d3e, meshVersion), namedObject));
  const m3dVersion = new Uint8Array(4);
  new DataView(m3dVersion.buffer).setUint32(0, 3, true);
  return enc(0x4d4d, concat(enc(0x0002, m3dVersion), editor));
}
